from pydantic import BaseModel, Field
from langchain_core.tools import tool
from langchain_openai import ChatOpenAI

# ── Define tools with Pydantic schemas ──────────────────────────────────────

class CalcInput(BaseModel):
    expression: str = Field(description="A valid Python arithmetic expression, e.g. '2 ** 10 + 3 * 7'")

class SearchInput(BaseModel):
    query: str = Field(description="A concise search query. Ask for facts, not analysis.")
    max_results: int = Field(default=3, ge=1, le=10)

@tool(args_schema=CalcInput)
def calculator(expression: str) -> str:
    """Evaluate arithmetic. Use for any numeric calculation. Never guess numbers."""
    try:
        # Restrict to safe subset
        allowed = set('0123456789 +-*/%().**eE')
        if not all(c in allowed for c in expression):
            return "Error: unsupported characters in expression"
        return str(eval(expression, {"__builtins__": {}}))
    except Exception as e:
        return f"Error: {e}"

@tool(args_schema=SearchInput)
def web_search(query: str, max_results: int = 3) -> str:
    """Search the web for current facts, events, or documentation."""
    # In production, call a real search API here
    return f"[stub] top {max_results} results for '{query}'"

# ── Register with model ──────────────────────────────────────────────────────

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)
tools = [calculator, web_search]

# bind_tools injects schemas into the API call
llm_with_tools = llm.bind_tools(tools)

# Each tool schema becomes an entry in the 'tools' API parameter:
