import asyncio
from langchain_core.messages import ToolMessage

async def execute_tool_calls_parallel(
    tool_calls: list[dict],
    tool_map: dict,
) -> list[ToolMessage]:
    """Execute multiple tool calls concurrently."""

    async def run_one(tc: dict) -> ToolMessage:
        tool_fn = tool_map.get(tc["name"])
        if tool_fn is None:
            result = f"Error: unknown tool '{tc['name']}'"
        else:
            try:
                # Use asyncio.to_thread for sync tools
                result = await asyncio.to_thread(tool_fn.invoke, tc["args"])
            except Exception as e:
                result = f"Tool error: {e}"
        return ToolMessage(content=str(result), tool_call_id=tc["id"])

    return await asyncio.gather(*[run_one(tc) for tc in tool_calls])

