from collections import Counter
from langchain_core.messages import HumanMessage, ToolMessage, AIMessage

class ToolCallGuard:
    """Detect and break tool-call loops."""

    def __init__(self, max_iterations: int = 12, dup_threshold: int = 2):
        self.max_iterations = max_iterations
        self.dup_threshold = dup_threshold
        self._seen: Counter = Counter()
        self._iteration = 0

    def check(self, tool_calls: list[dict]) -> str | None:
        """Return an error string if loop detected, else None."""
        self._iteration += 1
        if self._iteration > self.max_iterations:
            return f"Exceeded {self.max_iterations} iterations. Stop and summarise what you know."

        for tc in tool_calls:
            key = (tc["name"], str(sorted(tc["args"].items())))
            self._seen[key] += 1
            if self._seen[key] >= self.dup_threshold:
                return (
                    f"You have already called {tc['name']} with these arguments {self._seen[key]} times. "
                    f"The tool result will not change. Use the result you already have, or try a different approach."
                )
        return None

def guarded_loop(query: str, tools: list, llm_with_tools) -> str:
    tool_map = {t.name: t for t in tools}
    messages = [HumanMessage(content=query)]
    guard = ToolCallGuard()

    while True:
        response = llm_with_tools.invoke(messages)
        messages.append(response)

        if not response.tool_calls:
            return response.content

        # Check for loops before executing
        error = guard.check(response.tool_calls)
        if error:
            messages.append(HumanMessage(content=error))
            continue

        for tc in response.tool_calls:
            tool_fn = tool_map.get(tc["name"])
            result = tool_fn.invoke(tc["args"]) if tool_fn else f"Unknown tool: {tc['name']}"
            messages.append(ToolMessage(content=str(result), tool_call_id=tc["id"]))

from langgraph.prebuilt import create_react_agent
from langchain_core.messages import HumanMessage

graph = create_react_agent(llm, tools=[calculator, web_search])

# stream_mode="messages" yields (message, metadata) pairs
# allowing partial token display before tool calls complete
for chunk, metadata in graph.stream(
    {"messages": [HumanMessage(content="What is the population of Tokyo divided by 1000?")]},
    stream_mode="messages",
):
    if hasattr(chunk, "content") and chunk.content:
        # Print reasoning tokens as they arrive
        print(chunk.content, end="", flush=True)
    elif hasattr(chunk, "tool_calls") and chunk.tool_calls:
        for tc in chunk.tool_calls:
            print(f"\n[calling {tc['name']}({tc['args']})]...", flush=True)

# stream_mode="updates" yields graph state diffs — useful for debugging
for update in graph.stream(
    {"messages": [HumanMessage(content="How tall is Eiffel Tower in feet?")]},
    stream_mode="updates",
):
    node_name, state_diff = list(update.items())[0]
    print(f"--- {node_name} ---")
    for msg in state_diff.get("messages", []):
        print(f"  {type(msg).__name__}: {str(msg.content)[:80]}")
